using namespace std;

class Solution {
public:
    int flipLights(int n, int presses) {
        if (presses == 0) return 1;
        set<vector<bool>> states;
        for (int mask = 0; mask < 16; ++mask) {
            int b1 = (mask >> 3) & 1;
            int b2 = (mask >> 2) & 1;
            int b3 = (mask >> 1) & 1;
            int b4 = mask & 1;
            int sum = b1 + b2 + b3 + b4;
            if ((sum % 2) != (presses % 2)) continue;
            vector<bool> state(n, true);
            for (int i = 1; i <= n; ++i) {
                int flips = b1;
                if (i % 2 == 0) flips += b2;
                if (i % 2 == 1) flips += b3;
                if ((i - 1) % 3 == 0) flips += b4;
                state[i-1] = (flips % 2 == 0);
            }
            states.insert(state);
        }
        return states.size();
    }
};

